import{_ as i,o as a,c as t,ah as r}from"./chunks/framework.504LQ1l3.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"changelog-2026.3.1.md","filePath":"changelog-2026.3.1.md"}'),o={name:"changelog-2026.3.1.md"};function n(s,e,l,c,d,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="_2026-3-1-beta" tabindex="-1">[2026.3.1-beta] <a class="header-anchor" href="#_2026-3-1-beta" aria-label="Permalink to &quot;[2026.3.1-beta]&quot;">​</a></h2><h3 id="fifth-public-beta-release" tabindex="-1">Fifth Public Beta Release <a class="header-anchor" href="#fifth-public-beta-release" aria-label="Permalink to &quot;Fifth Public Beta Release&quot;">​</a></h3><p>The <strong>AI Security Gateway</strong> is a unified security platform providing real-time monitoring, policy enforcement, and threat detection for Large Language Model (LLM) APIs and Model Context Protocol (MCP) servers. This release introduces <strong>Guardrail Providers</strong> for real-time third-party content screening, a redesigned navigation layout, and a new visual Pipeline view for OAuth access management.</p><hr><h4 id="🛡️-guardrail-providers" tabindex="-1">🛡️ Guardrail Providers <a class="header-anchor" href="#🛡️-guardrail-providers" aria-label="Permalink to &quot;🛡️ Guardrail Providers&quot;">​</a></h4><p>A new integration layer that connects the AI Security Gateway to third-party guardrail services for real-time content screening of LLM requests and responses. Multiple providers can run concurrently using a fan-out/fan-in pattern, where total latency equals the slowest provider rather than the sum.</p><p><strong>Supported providers:</strong></p><ul><li><strong>Groq Safeguard</strong> : High-speed safety classification with configurable safety policy prompts</li><li><strong>EnkryptAI</strong> : Comprehensive guardrail API with policy-based detection across NSFW, toxicity, PII, injection attacks, and more</li><li><strong>DynamoAI DynamoGuard</strong> : Multi-policy moderation with per-policy scoring for prompt injection, toxicity, PII, hate speech, and violence</li><li><strong>GuardrailsAI</strong> : Self-hosted, open-source guardrail with 67+ validators from Guardrails Hub covering jailbreak detection, PII, toxicity, and content policy</li><li><strong>Fiddler AI Guardrails</strong> : Sub-second safety classification across 11 dimensions with optional 24-type PII detection</li></ul><p><strong>Key features:</strong></p><ul><li><strong>Per-Proxy &amp; Per-Team Assignment</strong>: Apply providers globally to a proxy or scope them to specific teams for layered screening</li><li><strong>Configurable Behaviour</strong>: Set direction (request/response/both), action (block/monitor), failure mode (fail-open/fail-closed), timeout (500ms–60s), and priority</li><li><strong>Health Checks &amp; Test Playground</strong>: Verify provider connectivity and test content screening directly from the dashboard</li><li><strong>Audit Logging</strong>: Every provider check is logged with verdict, categories, confidence score, latency, and tokens used</li><li><strong>Dashboard &amp; Metrics</strong>: Per-provider and per-proxy statistics with top violation category breakdowns</li></ul><hr><h4 id="🧪-guardrail-evaluation-enhancements" tabindex="-1">🧪 Guardrail Evaluation Enhancements <a class="header-anchor" href="#🧪-guardrail-evaluation-enhancements" aria-label="Permalink to &quot;🧪 Guardrail Evaluation Enhancements&quot;">​</a></h4><p>Guardrail Evaluations can now target <strong>configured Guardrail Providers directly</strong>, in addition to HTTP endpoints. This makes it easy to benchmark provider detection rates against the built-in 71 test cases across 12 attack categories without needing to set up a separate endpoint.</p><hr><h4 id="🔔-granular-alert-notifications" tabindex="-1">🔔 Granular Alert Notifications <a class="header-anchor" href="#🔔-granular-alert-notifications" aria-label="Permalink to &quot;🔔 Granular Alert Notifications&quot;">​</a></h4><p>Email and Slack integrations now support fine-grained control over which alerts trigger notifications:</p><ul><li><strong>Per-Category Filtering</strong>: Enable or disable notifications for specific alert categories : policy violations, tool access attempts, security events, system events, and compliance alerts</li><li><strong>Minimum Severity Threshold</strong>: Set a minimum severity level (Critical, High, Medium, Low, Info) per integration channel</li><li>Each integration channel can be configured independently</li></ul><hr><h4 id="🧭-redesigned-navigation" tabindex="-1">🧭 Redesigned Navigation <a class="header-anchor" href="#🧭-redesigned-navigation" aria-label="Permalink to &quot;🧭 Redesigned Navigation&quot;">​</a></h4><p>The main sidebar navigation has been reorganised for improved clarity as the platform grows:</p><ul><li><strong>Security Tools</strong>: Hosts System Prompts, Canary Detection, and the Skill Security Hub</li><li><strong>Guardrails</strong>: New menu group for Guardrail Providers and Guardrail Evaluations</li><li><strong>Access &amp; Identity</strong>: Teams &amp; API Keys, OAuth Access, OAuth Proxy, User Activity, and Playground</li><li><strong>Infrastructure</strong>: Proxy Management, A2A Agents, and Audit Logs</li></ul><hr><h4 id="🔀-oauth-access-pipeline-view" tabindex="-1">🔀 OAuth Access Pipeline View <a class="header-anchor" href="#🔀-oauth-access-pipeline-view" aria-label="Permalink to &quot;🔀 OAuth Access Pipeline View&quot;">​</a></h4><p>A new visual Pipeline view for OAuth Access Management that shows the full user journey from provider to permissions:</p><p><strong>Provider → Rules → Teams → Users → Tool Overrides → Summary</strong></p><p>Each stage is an interactive section where administrators can drill into provider configurations, group assignment rules, team memberships, individual users, and per-user tool permission overrides. A summary bar displays quick statistics across the pipeline. The view mode (Pipeline or Table) is persisted across sessions.</p><hr><h4 id="🐛-bug-fixes-improvements" tabindex="-1">🐛 Bug Fixes &amp; Improvements <a class="header-anchor" href="#🐛-bug-fixes-improvements" aria-label="Permalink to &quot;🐛 Bug Fixes &amp; Improvements&quot;">​</a></h4><ul><li>Improvements to Canary Token Detection reliability and accuracy</li><li>System Prompt Injection stability fixes</li><li>External Storage sync and configuration improvements</li><li>General UI polish and consistency updates</li></ul>',29)])])}const h=i(o,[["render",n]]);export{p as __pageData,h as default};
